import{_ as o,o as e,c as l,a3 as a}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"组件测试器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/component-tester.md","filePath":"user-guide/tools/component-tester.md","lastUpdated":1778221347000}'),r={name:"user-guide/tools/component-tester.md"};function i(n,t,d,s,c,u){return e(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="组件测试器" tabindex="-1">组件测试器 <a class="header-anchor" href="#组件测试器" aria-label="Permalink to &quot;组件测试器&quot;">​</a></h1><blockquote><p>开发调试与 UI 验证的&quot;试验场&quot;，集中展示、测试和验证应用中各种 UI 组件的表现。</p></blockquote><p><img src="" alt="TODO: 组件测试器主界面截图"></p><h2 id="功能要点" tabindex="-1">功能要点 <a class="header-anchor" href="#功能要点" aria-label="Permalink to &quot;功能要点&quot;">​</a></h2><ul><li><strong>组件展示</strong> — 集中展示各类 UI 组件（包括自定义组件和 Element Plus 组件）的使用示例，快速了解组件能力。</li><li><strong>交互测试</strong> — 手动测试组件的交互行为和边界情况，确保功能正确性。</li><li><strong>主题验证</strong> — 验证应用在不同主题（亮色/暗色）下的颜色、样式和布局是否一致。</li><li><strong>性能基准</strong> — 内置存储性能测试方案，对比不同序列化/读写策略的耗时差异。</li><li><strong>窗口分离体系演示</strong> — 真实体验 <code>useDetachable</code> 与 <code>useDetachedManager</code> 的协同工作流程。</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><ol><li>在侧边栏找到 <strong>组件测试器</strong> 图标（烧瓶图标），点击进入。</li><li>默认打开 <strong>原生元素</strong> 标签页，可以查看标题、文本、按钮、输入框等 HTML 原生元素在当前主题下的样式效果。</li><li>依次切换其他标签页，逐一测试各类组件的功能和外观。</li><li>在 <strong>消息提示</strong> 标签页中，点击各按钮可触发不同类型的消息弹窗和通知。</li><li>在 <strong>存储性能测试</strong> 标签页中，点击 <code>运行全部方案</code> 即可对比六种不同存储策略的性能数据。</li></ol><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="原生元素" tabindex="-1">原生元素 <a class="header-anchor" href="#原生元素" aria-label="Permalink to &quot;原生元素&quot;">​</a></h3><p>展示所有 HTML 原生标签在当前主题下的样式表现，包括：</p><ul><li>标题层级 <code>h1</code> ~ <code>h6</code></li><li>文本元素（段落、加粗、斜体、链接、代码块、引用块等）</li><li>按钮（默认/主要/成功/圆角/禁用/不同尺寸）</li><li>输入框（文本、密码、数字、邮箱、日期、颜色选择、文件、范围滑块）</li><li>选择元素（下拉框、文本域）</li><li>复选框与单选框（含选中状态、禁用状态）</li><li>列表（有序/无序/描述列表）</li><li>表格、详情折叠、进度条、字段集</li></ul><blockquote><p>用途：快速查看全局样式是否统一、浏览器默认样式是否被正确覆盖。</p></blockquote><h3 id="elementplus-组件" tabindex="-1">ElementPlus 组件 <a class="header-anchor" href="#elementplus-组件" aria-label="Permalink to &quot;ElementPlus 组件&quot;">​</a></h3><p>展示 Element Plus 官方组件的完整使用示例，包括：</p><ul><li>Button（类型、朴素、圆角、圆形、禁用、加载、尺寸）</li><li>Input（清除按钮、图标、密码、文本域）</li><li>Select（单选、可清空、多选）</li><li>Switch、Radio、Checkbox（含按钮样式）</li><li>DatePicker（日期、日期时间、日期范围）</li><li>Slider（含输入框、范围模式）</li><li>Tag、Progress（含环形、仪表盘）、Badge</li><li>Card（自定义 InfoCard 与原生 el-card 对比）</li><li>Collapse、Timeline、Table、Pagination、Steps</li><li>Dialog（BaseDialog 与 el-dialog 对比）、Drawer</li><li>Popconfirm、Tooltip、Popover、Tree、Loading、Skeleton、Empty、Result</li></ul><blockquote><p>提示：部分组件（如 Dialog）展示了<strong>自定义封装</strong>（BaseDialog）与<strong>原生组件</strong>（el-dialog）的对比，便于评估封装效果。</p></blockquote><h3 id="窗口分离与同步" tabindex="-1">窗口分离与同步 <a class="header-anchor" href="#窗口分离与同步" aria-label="Permalink to &quot;窗口分离与同步&quot;">​</a></h3><p>演示 <strong>窗口分离体系</strong> 的核心能力：</p><ul><li><strong>同步数据演示</strong> — 点击&quot;分离组件到新窗口&quot;后，组件会在悬浮窗中运行；在悬浮窗中修改计数器、文本、深度对象等数据，主窗口的预览卡片会<strong>实时同步</strong>更新。</li><li><strong>远程 Action (RPC)</strong> — 分离窗口可通过 Action 机制触发主窗口的逻辑（如弹出通知），实现跨窗口通信。</li><li><strong>布局预览</strong> — 展示 <code>ComponentHeader</code> 在 <code>top</code>、<code>bottom</code>、<code>left</code>、<code>right</code> 四种位置下的样式与拖拽分离效果。</li></ul><p><img src="" alt="TODO: 窗口分离同步演示截图"></p><h3 id="消息提示" tabindex="-1">消息提示 <a class="header-anchor" href="#消息提示" aria-label="Permalink to &quot;消息提示&quot;">​</a></h3><p>测试全局消息反馈系统的各项功能：</p><table tabindex="0"><thead><tr><th>类别</th><th>说明</th></tr></thead><tbody><tr><td><strong>ElMessage</strong></td><td>Element Plus 标准消息提示（成功/信息/警告/错误），含 HTML 内容、可关闭、居中、分组、长文本</td></tr><tr><td><strong>CustomMessage</strong></td><td>项目封装的 <code>customMessage</code>，自动避开自定义标题栏的 <code>offset</code></td></tr><tr><td><strong>ElNotification</strong></td><td>通知弹窗（支持四个角落位置、不自动关闭、HTML 内容、长文本）</td></tr><tr><td><strong>ElMessageBox</strong></td><td>消息弹框（Alert / Confirm / Prompt），含自定义图标、HTML 内容、长文本</td></tr><tr><td><strong>通知系统</strong></td><td>使用 <code>useNotification</code> 的持久化消息系统，支持通知中心面板、全部标记已读、清空历史</td></tr></tbody></table><blockquote><p>场景：开发者在添加新的消息提示时，可在此验证其在不同场景下的表现。</p></blockquote><h3 id="主题色板" tabindex="-1">主题色板 <a class="header-anchor" href="#主题色板" aria-label="Permalink to &quot;主题色板&quot;">​</a></h3><p>动态展示当前主题下的所有 CSS 颜色变量：</p><ul><li><strong>主题色系</strong> — Primary / Success / Warning / Danger / Info 各 9 级 Light 变体</li><li><strong>文本颜色</strong> — Primary / Regular / Secondary / Placeholder</li><li><strong>边框颜色</strong> — Darker / Dark / Base / Light / Lighter</li><li><strong>填充颜色</strong> — Darker / Dark / Base / Light / Lighter</li><li><strong>背景颜色</strong> — Base / Page / Overlay</li><li><strong>遮罩颜色</strong> — Mask / Extra Light</li></ul><blockquote><p>注意：切换主题（亮色/暗色）后色板会自动刷新，可用于验证主题色彩系统的一致性。</p></blockquote><h3 id="文档查看器" tabindex="-1">文档查看器 <a class="header-anchor" href="#文档查看器" aria-label="Permalink to &quot;文档查看器&quot;">​</a></h3><p>验证 <code>DocumentViewer</code> 组件对不同内容类型的渲染能力：</p><ul><li><strong>Markdown 预览</strong> — 从字符串渲染带代码块、引用、列表等内容的 Markdown</li><li><strong>JSON 源码视图</strong> — 展示 JSON 格式化后的源码（带编辑器引擎切换）</li><li><strong>纯文本视图</strong> — 简单文本文件预览</li><li><strong>二进制文件占位符</strong> — 遇到不可渲染的二进制格式时优雅降级</li><li><strong>空内容</strong> — 空白文件的状态展示</li><li><strong>文件不存在</strong> — 模拟加载失败时的错误提示</li></ul><p><img src="" alt="TODO: 文档查看器测试界面截图"></p><h3 id="存储性能测试" tabindex="-1">存储性能测试 <a class="header-anchor" href="#存储性能测试" aria-label="Permalink to &quot;存储性能测试&quot;">​</a></h3><p>对比六种不同序列化与读写策略的性能差异，适用于评估聊天记录等大数据的持久化方案：</p><table tabindex="0"><thead><tr><th>方案</th><th>描述</th><th>关键差异</th></tr></thead><tbody><tr><td><strong>A</strong></td><td>Vec&lt;u8&gt; + 美化 JSON</td><td>传统 IPC 方式，有数据膨胀</td></tr><tr><td><strong>B</strong></td><td>文本直传 + 紧凑 JSON</td><td>零膨胀，String 直传</td></tr><tr><td><strong>C</strong></td><td>伪二进制 (Vec&lt;u8&gt;)</td><td>读取时经历额外解码</td></tr><tr><td><strong>D</strong></td><td>直传写入 + 二进制读取</td><td>读取端零膨胀</td></tr><tr><td><strong>E</strong></td><td>增量更新 (JSON Patch)</td><td>只传输变更部分，网络友好</td></tr><tr><td><strong>F</strong></td><td>生产环境模拟 (plugin-fs)</td><td>模拟实际业务中的数据清洗 + 标准通道</td></tr></tbody></table><blockquote><p>操作：调整&quot;消息数量&quot;和&quot;单条长度&quot;后点击&quot;运行全部方案&quot;，结果以表格展示各方案的耗时对比，并标注相对基准的百分比差异。</p></blockquote><h3 id="下载测试" tabindex="-1">下载测试 <a class="header-anchor" href="#下载测试" aria-label="Permalink to &quot;下载测试&quot;">​</a></h3><p>测试文件下载流程与拖放功能：</p><ul><li><strong>下载模式</strong> — 支持&quot;自动（静默）&quot;和&quot;手动（另存为）&quot;两种模式</li><li><strong>预设测试</strong> — 快速测试文本、JSON、图片和 10MB 大文件下载</li><li><strong>拖放测试</strong> — 将文件拖入 <code>DropZone</code> 区域后，可重新下载该文件</li><li><strong>下载历史</strong> — 右侧面板展示 <code>DownloadManager</code> 的历史记录</li></ul><p><img src="" alt="TODO: 下载测试界面截图"></p><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="验证新组件的主题兼容性" tabindex="-1">验证新组件的主题兼容性 <a class="header-anchor" href="#验证新组件的主题兼容性" aria-label="Permalink to &quot;验证新组件的主题兼容性&quot;">​</a></h3><p>当你开发了一个新的自定义组件，不确定它在暗色模式和透明度设置下是否兼容，可以：</p><ol><li>将新组件临时添加到 <strong>原生元素</strong> 或 <strong>ElementPlus 组件</strong> 标签页中。</li><li>点击右上角的主题切换，观察组件在暗色模式下的表现。</li><li>在设置中调整&quot;界面质感&quot;（透明度、模糊强度），确认组件能正确响应变化。</li></ol><h3 id="评估存储方案" tabindex="-1">评估存储方案 <a class="header-anchor" href="#评估存储方案" aria-label="Permalink to &quot;评估存储方案&quot;">​</a></h3><p>在开发涉及大量数据持久化的功能（如聊天记录存档）时：</p><ol><li>进入 <strong>存储性能测试</strong> 标签页。</li><li>调整&quot;消息数量&quot;和&quot;单条长度（KB）&quot;来模拟真实数据规模。</li><li>点击&quot;运行全部方案&quot;，从结果表格中找出总耗时最低和文件体积最小的方案。</li><li>展开方案行查看详细步骤，定位性能瓶颈。</li></ol><h3 id="调试窗口分离逻辑" tabindex="-1">调试窗口分离逻辑 <a class="header-anchor" href="#调试窗口分离逻辑" aria-label="Permalink to &quot;调试窗口分离逻辑&quot;">​</a></h3><p>如果发现某个可分离组件在分离后状态不同步：</p><ol><li>进入 <strong>窗口分离与同步</strong> 标签页。</li><li>点击&quot;分离组件到新窗口&quot;，在悬浮窗中修改同步数据。</li><li>观察主窗口的预览卡片是否实时更新；如果未更新，检查 <code>useStateSyncEngine</code> 的 <code>stateKey</code> 和 <code>autoPush</code> 配置。</li><li>点击&quot;触发主窗口通知&quot;验证跨窗口 Action (RPC) 是否正常工作。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么点击按钮没有弹出消息提示" tabindex="-1">为什么点击按钮没有弹出消息提示？ <a class="header-anchor" href="#为什么点击按钮没有弹出消息提示" aria-label="Permalink to &quot;为什么点击按钮没有弹出消息提示？&quot;">​</a></h3><p>某些消息测试（如 <code>ElMessage</code>）默认会自动关闭。如果网络卡顿或操作过快可能错过显示。可以尝试：</p><ul><li>点击 <strong>可关闭消息</strong> 按钮（设置了 <code>duration: 0</code>，不会自动关闭）</li><li>检查浏览器/应用是否处于焦点状态</li></ul><h3 id="存储性能测试的-预计大小-和实际文件大小不一致" tabindex="-1">存储性能测试的&quot;预计大小&quot;和实际文件大小不一致？ <a class="header-anchor" href="#存储性能测试的-预计大小-和实际文件大小不一致" aria-label="Permalink to &quot;存储性能测试的&quot;预计大小&quot;和实际文件大小不一致？&quot;">​</a></h3><p>&quot;预计大小&quot;是基于<strong>消息数量 × 单条长度</strong>的<strong>粗略估算</strong>，实际数据因 JSON 序列化后的字段名称、嵌套结构等因素会有所差异。最终以结果表中的&quot;文件大小&quot;列显示为准。</p><h3 id="文档查看器测试中的-文件不存在-显示空白" tabindex="-1">文档查看器测试中的&quot;文件不存在&quot;显示空白？ <a class="header-anchor" href="#文档查看器测试中的-文件不存在-显示空白" aria-label="Permalink to &quot;文档查看器测试中的&quot;文件不存在&quot;显示空白？&quot;">​</a></h3><p>这是正常行为。<code>DocumentViewer</code> 在检测到文件无法读取时会显示友好的错误提示。如果你的测试文件路径有效但依然显示空白，请检查路径中的文件名和扩展名是否正确。</p><h3 id="窗口分离后-修改数据主窗口没有同步" tabindex="-1">窗口分离后，修改数据主窗口没有同步？ <a class="header-anchor" href="#窗口分离后-修改数据主窗口没有同步" aria-label="Permalink to &quot;窗口分离后，修改数据主窗口没有同步？&quot;">​</a></h3><p>请确认：</p><ul><li>分离窗口的 <code>stateKey</code> 与主窗口的 <code>useStateSyncEngine</code> 配置一致（默认为 <code>component-tester:sync-demo-data</code>）。</li><li><code>autoPush</code> 和 <code>autoReceive</code> 都设置为 <code>true</code>。</li><li>深度嵌套的对象（如 <code>nested.b.c</code>）修改后会通过 <code>requestUpdateSyncData</code> 触发 Action 同步。</li></ul><h3 id="下载测试中的-自动模式-和-手动模式-有什么区别" tabindex="-1">下载测试中的&quot;自动模式&quot;和&quot;手动模式&quot;有什么区别？ <a class="header-anchor" href="#下载测试中的-自动模式-和-手动模式-有什么区别" aria-label="Permalink to &quot;下载测试中的&quot;自动模式&quot;和&quot;手动模式&quot;有什么区别？&quot;">​</a></h3><ul><li><strong>自动模式</strong>：将文件保存到设置的默认下载目录，无需用户确认。</li><li><strong>手动模式</strong>：弹出原生系统&quot;另存为&quot;对话框，让用户选择保存位置和文件名。两者在下载历史中都会记录。</li></ul>',63)])])}const q=o(r,[["render",i]]);export{h as __pageData,q as default};
